-- ----------------------------------------------------------------------------
-- SOURCE: 027_project_constraints.sql
-- ----------------------------------------------------------------------------
-- ============================================================
-- 027_project_constraints.sql
-- 1. Add missing columns to projects table
-- 2. Enforce 1-project-per-employee at the DB level via trigger
-- ============================================================

-- ─── Add missing columns ─────────────────────────────────────

ALTER TABLE public.projects
    ADD COLUMN IF NOT EXISTS location_address    text,
    ADD COLUMN IF NOT EXISTS verification_method text DEFAULT 'face_or_qr'
        CHECK (verification_method IN ('face_only','qr_only','face_or_qr','manual_only')),
    ADD COLUMN IF NOT EXISTS require_geofence    boolean NOT NULL DEFAULT true,
    ADD COLUMN IF NOT EXISTS geofence_radius_meters double precision;

-- ─── Function: enforce 1 project per employee ────────────────
--
-- Before any INSERT or UPDATE on projects, check that none of the
-- NEW row's assigned_employee_ids already appear in any OTHER project.
-- If they do, strip them from the OTHER project(s) atomically.
--
-- This mirrors the Zustand store logic: "move" the employee instead
-- of blocking the operation, so the app's intent is always honoured.

CREATE OR REPLACE FUNCTION public.enforce_one_project_per_employee()
RETURNS TRIGGER
LANGUAGE plpgsql
AS $$
DECLARE
    emp_id text;
BEGIN
    -- For each employee being assigned to the NEW row...
    FOREACH emp_id IN ARRAY NEW.assigned_employee_ids
    LOOP
        -- Remove that employee from every OTHER project row
        UPDATE public.projects
        SET assigned_employee_ids = array_remove(assigned_employee_ids, emp_id)
        WHERE id <> NEW.id
          AND emp_id = ANY(assigned_employee_ids);
    END LOOP;

    RETURN NEW;
END;
$$;

-- Drop old version if exists, then recreate
DROP TRIGGER IF EXISTS trg_one_project_per_employee ON public.projects;

CREATE TRIGGER trg_one_project_per_employee
    BEFORE INSERT OR UPDATE OF assigned_employee_ids
    ON public.projects
    FOR EACH ROW
    EXECUTE FUNCTION public.enforce_one_project_per_employee();

-- ─── Grant execute on the function ───────────────────────────

GRANT EXECUTE ON FUNCTION public.enforce_one_project_per_employee() TO authenticated;
GRANT EXECUTE ON FUNCTION public.enforce_one_project_per_employee() TO service_role;


-- ----------------------------------------------------------------------------
-- SOURCE: 029_project_assignments_junction.sql
-- ----------------------------------------------------------------------------
-- ============================================================
-- 029_project_assignments_junction.sql
-- Replace projects.assigned_employee_ids text[] with proper
-- junction table for FK enforcement and indexing.
-- ============================================================

-- ─── Junction table ──────────────────────────────────────────

CREATE TABLE IF NOT EXISTS public.project_assignments (
    project_id   text NOT NULL REFERENCES public.projects(id) ON DELETE CASCADE,
    employee_id  text NOT NULL REFERENCES public.employees(id) ON DELETE CASCADE,
    assigned_at  timestamptz NOT NULL DEFAULT now(),
    PRIMARY KEY (project_id, employee_id)
);

CREATE INDEX IF NOT EXISTS idx_pa_employee ON public.project_assignments(employee_id);

ALTER TABLE public.project_assignments ENABLE ROW LEVEL SECURITY;

-- RLS: readable by all (matches projects table), writable by admin/hr/supervisor
CREATE POLICY "project_assignments_read"
    ON public.project_assignments
    FOR SELECT
    TO authenticated
    USING (true);

CREATE POLICY "project_assignments_write"
    ON public.project_assignments
    FOR ALL
    TO authenticated
    USING (
        public.get_user_role() IN ('admin', 'hr', 'supervisor')
    )
    WITH CHECK (
        public.get_user_role() IN ('admin', 'hr', 'supervisor')
    );

-- ─── Migrate existing data ───────────────────────────────────

INSERT INTO public.project_assignments (project_id, employee_id)
SELECT p.id, unnest(p.assigned_employee_ids)
FROM public.projects p
WHERE array_length(p.assigned_employee_ids, 1) > 0
ON CONFLICT DO NOTHING;

-- ─── Update the enforce_one_project_per_employee trigger ─────
-- Now operates on the junction table instead of array column.

CREATE OR REPLACE FUNCTION public.enforce_one_project_per_employee()
RETURNS TRIGGER
LANGUAGE plpgsql
AS $$
BEGIN
    -- When an assignment is inserted, remove that employee
    -- from any OTHER project (enforce 1 project per employee).
    DELETE FROM public.project_assignments
    WHERE employee_id = NEW.employee_id
      AND project_id <> NEW.project_id;

    RETURN NEW;
END;
$$;

-- Drop old trigger (was on projects table)
DROP TRIGGER IF EXISTS trg_one_project_per_employee ON public.projects;

-- New trigger on the junction table
DROP TRIGGER IF EXISTS trg_one_project_per_employee ON public.project_assignments;
CREATE TRIGGER trg_one_project_per_employee
    BEFORE INSERT
    ON public.project_assignments
    FOR EACH ROW
    EXECUTE FUNCTION public.enforce_one_project_per_employee();

-- ─── Keep old column but mark deprecated ─────────────────────
COMMENT ON COLUMN public.projects.assigned_employee_ids
    IS 'DEPRECATED — use project_assignments junction table. Will be removed in a future migration.';


