-- ─── Task Tags Table ──────────────────────────────────────────
-- Provides a managed registry of tags that admins can define,
-- each with a display name and a hex colour.  Tasks reference
-- tags by name (string[]), so this table is purely metadata.

CREATE TABLE IF NOT EXISTS public.task_tags (
    id          text        PRIMARY KEY,
    name        text        NOT NULL UNIQUE,
    color       text        NOT NULL DEFAULT '#6366f1',
    created_by  text        NOT NULL,
    created_at  timestamptz NOT NULL DEFAULT now()
);

-- Full access for authenticated users (admin manages in UI)
ALTER TABLE public.task_tags ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Authenticated users can read task_tags"
    ON public.task_tags FOR SELECT
    TO authenticated
    USING (true);

CREATE POLICY "Authenticated users can insert task_tags"
    ON public.task_tags FOR INSERT
    TO authenticated
    WITH CHECK (true);

CREATE POLICY "Authenticated users can update task_tags"
    ON public.task_tags FOR UPDATE
    TO authenticated
    USING (true);

CREATE POLICY "Authenticated users can delete task_tags"
    ON public.task_tags FOR DELETE
    TO authenticated
    USING (true);

-- Index for quick name lookups / auto-complete
CREATE INDEX IF NOT EXISTS idx_task_tags_name ON public.task_tags (lower(name));


-- ----------------------------------------------------------------------------
-- SOURCE: 046_text_channels_realtime.sql
-- ----------------------------------------------------------------------------
-- Migration 046: Enable Supabase Realtime for text_channels
--
-- The text_channels table was missing from realtime publication.
-- This enables real-time channel creation, updates, and deletions
-- to sync across all connected clients.

DO $$
BEGIN
  -- Set REPLICA IDENTITY FULL for complete UPDATE payloads
  IF EXISTS (
    SELECT 1 FROM pg_class c
    JOIN pg_namespace n ON n.oid = c.relnamespace
    WHERE n.nspname = 'public' AND c.relname = 'text_channels' AND c.relkind = 'r'
  ) THEN
    ALTER TABLE public.text_channels REPLICA IDENTITY FULL;
  END IF;

  -- Add to supabase_realtime publication
  IF EXISTS (
    SELECT 1 FROM pg_class c
    JOIN pg_namespace n ON n.oid = c.relnamespace
    WHERE n.nspname = 'public' AND c.relname = 'text_channels' AND c.relkind = 'r'
  ) THEN
    BEGIN
      ALTER PUBLICATION supabase_realtime ADD TABLE public.text_channels;
    EXCEPTION WHEN duplicate_object THEN NULL;
    END;
  END IF;
END;
$$;


